var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"신이시여.","JPN":"神よ。","ENG":"When I am called to duty, God.","TWN":"神哪。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"제가 부름을 받을 때에는.","JPN":"私が呼び出されたときには、","ENG":"Wherever flames may rage.","TWN":"當我執行勤務時，"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"아무리 맹렬한 화염속에서도.","JPN":"たとえ業火の中であろうと、","ENG":"Give me the strength to save a life.","TWN":" 儘管火焰總是那麼猛烈，"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"한 생명을 구할 수 있는 힘을 저에게 주소서.","JPN":"尊い命を救うための、強靭な力を与え給え。","ENG":"Whatever by its age.","TWN":"請賜給我力量去拯救生命。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"제안. 포기하십시오.","JPN":"提案。諦めてください。","ENG":"Suggestion. Give up.","TWN":"提議。放棄。"},"stage":{"bg":"SPACE_GRAVITY","slots":{"L":null,"C":{"char_id":"SIMURGH_NPC_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"바이탈 체크. 이미 침식 증후군 증세를 보이고 있습니다.","JPN":"バイタルチェック。すでに侵食症候群の症状が現れています。","ENG":"Checking vital signs. You are already showing signs of Corruption Syndrome.","TWN":"確認生命跡象。你已出現了侵蝕症候群的跡象。"},"stage":{"bg":"SPACE_GRAVITY","slots":{"L":null,"C":{"char_id":"SIMURGH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"시끄러워……!!","JPN":"うるさい……！！","ENG":"Shut up...!!","TWN":"閉嘴……！！"},"stage":{"bg":"SPACE_GRAVITY","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"여기서 너희를 막지 않으면, 또 쓸데없는 이유로 수많은 사람을 죽일 거잖아!","JPN":"ここでおまえらを止めないと、またくだらない理由でたくさんの人が死ぬことになる！","ENG":"If I don't stop you here, you're going to kill more people for your stupid reasons!","TWN":"如果不在這裡阻止你們，又會有許多無辜的人因你們而喪命！"},"stage":{"bg":"SPACE_GRAVITY","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"부정. 쓸데없지 않습니다.","JPN":"否定。くだらなくはありません。","ENG":"Negative. It is not stupid.","TWN":"否定。這毫無用處。"},"stage":{"bg":"SPACE_GRAVITY","slots":{"L":null,"C":{"char_id":"SIMURGH_NPC_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"냉동수면이 유지되는 동안, 인간. 자신이 바라는 세계에서 바라는 삶을 살게 됩니다.","JPN":"冷凍保存が維持されている間、人間は理想の世界で理想の人生を歩むことができます。","ENG":"While you are in cryogenic sleep, human, you will live in the world you always wanted.","TWN":"冷凍休眠期間，你會在你想要的世界裡過你想要的生活。人類。"},"stage":{"bg":"SPACE_GRAVITY","slots":{"L":null,"C":{"char_id":"SIMURGH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"연합의 인류 대부분 스스로 보존되는 걸 택했습니다.","JPN":"連合のほとんどの人類は、自ら保存されることを選びました。","ENG":"Most of the humans in the Interstellar Alliance have already chosen preservation.","TWN":"聯盟的大部分人類選擇了保存。"},"stage":{"bg":"SPACE_GRAVITY","slots":{"L":null,"C":{"char_id":"SIMURGH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"육체가 아닌, 정신의 자유. 그것이 연합이 선택한 최선의 선택.","JPN":"肉体ではなく、精神の自由。それこそ、連合が選んだ最善の選択。","ENG":"A freedom of mind, not the body. That is the Interstellar Alliance's best choice.","TWN":"心靈的自由，不是身體的自由。這對聯盟來說是最好的選擇。"},"stage":{"bg":"SPACE_GRAVITY","slots":{"L":null,"C":{"char_id":"SIMURGH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SIMURGH_NPC_NULL_NULL","text":{"KOREA":"인류가 멸망을 피할 수 있는 유일한 방법입니다.","JPN":"人類が滅亡を避けられる唯一の方法です。","ENG":"It is the only way to avoid humanity's destruction.","TWN":"這是人類避免毀滅的唯一途徑。"},"stage":{"bg":"SPACE_GRAVITY","slots":{"L":null,"C":{"char_id":"SIMURGH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"narration","speaker":null,"text":{"KOREA":"제 소명을 수행케 하시고.","JPN":"私が天職に従い。","ENG":"I want to fill my calling,","TWN":"請讓我履行使命。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"narration","speaker":null,"text":{"KOREA":"언제나 최선을 다할 수 있게 도와주시옵소서.","JPN":"いつでも全力を出せるよう、私をお助けください。","ENG":"and give the best in me.","TWN":"幫助我盡力而為。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"웃기지 마……!! 그딴 게 최선이라고……!?","JPN":"ふざけるな……！！　それが最善だって……！？","ENG":"Don't make me laugh...! That's the best choice...?!","TWN":"開什麼玩笑……！！這就是最好的了……？！"},"stage":{"bg":"SPACE_GRAVITY","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"그건 그냥 도망친 것뿐이잖아……!!","JPN":"それはただ逃げただけじゃないか……！！","ENG":"That's just running away...!!","TWN":"這不就是逃跑嗎……！！"},"stage":{"bg":"SPACE_GRAVITY","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CAT_YAKSHA_NULL_NULL","text":{"KOREA":"나에게 있어서 최선이라는 건……!!","JPN":"アタシにとって最善ってのは……！！","ENG":"The best choice for me is...!","TWN":"對我來說最好的選擇是……！！"},"stage":{"bg":"SPACE_GRAVITY","slots":{"L":null,"C":{"char_id":"CAT_YAKSHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAP","text":{"KOREA":"훌륭한 소방관이라면, 구조자의 목숨과 자신의 목숨……. 어느 쪽도 놓치지 않는다.","JPN":"立派な消防士なら、救助者の命と自分の命……どっちも取りこぼさない。","ENG":"An excellent firefighter knows how to save both... the rescuee's and the rescuer's lives.","TWN":"一名優秀的消防員，求救者和自己的生命……任何一方都不能放棄。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAP","text":{"KOREA":"마지막까지 최선을 다하되, 자기 목숨까지 버리지는 말아라.","JPN":"最後までベストを尽くせ。だが、自分の命も守るんだ。","ENG":"I'm telling you to do your best until the very end, but not throw away your own life.","TWN":"竭盡我們最大的努力，但不許把自己的命也賠進去！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_Q","text":{"KOREA":"그 화재로 동료분들을 잃으셨다고 들었어요.","JPN":"あの火災で同僚の方々が亡くなられたと聞きました。","ENG":"I heard you lost a lot of colleagues to that fire.","TWN":"我聽說你在那場火災中失去了很多同事。"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_Q","text":{"KOREA":"하지만 최선을 다하셨는데, 그렇게까지 자책하실 필요는 없다고 생각해요.","JPN":"でも、ベストを尽くしたのにそこまで自分を責める必要はないと思います。","ENG":"But you did your best, so there's no need to keep blaming yourself.","TWN":"但你已經盡力了，我認為你不必太自責。"},"stage":{"bg":"FALL_PARK","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"네가 관리국에…… 그리고 야크샤에게 반드시 필요한 사람이었기 때문이었어.","JPN":"あなたが管理局に……そしてヤクシャーに必ず必要な人間だったからよ。","ENG":"It was because... you were someone the Administration and Yaksha needed.","TWN":"你對於管理局……對於夜叉來說，都是不可缺少的存在。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};